// This function simulates running the user's compiled program with a given input.
// It assumes the user's code is compiled into an executable named "a.out".
std::string run_user_code(const std::string& input_str) {
    std::string temp_input_filename = "temp_input.txt";
    std::string temp_output_filename = "temp_output.txt";
    std::string program_executable = "./a.out"; 

    // Write input to a temporary file
    std::ofstream input_file(temp_input_filename);
    if (!input_file.is_open()) return "ERROR: Could not create temp_input.txt";
    input_file << input_str;
    input_file.close();

    // Run the user's program, redirecting stdin and stdout
    std::string command = program_executable + " < " + temp_input_filename + " > " + temp_output_filename + " 2>&1";
    int system_result = system(command.c_str()); // Execute command

    // Read output from the temporary file
    std::ifstream output_file(temp_output_filename);
    if (!output_file.is_open()) return "ERROR: Could not open temp_output.txt";
    std::stringstream buffer;
    buffer << output_file.rdbuf();
    output_file.close();

    // Clean up temporary files
    remove(temp_input_filename.c_str());
    remove(temp_output_filename.c_str());

    return buffer.str();
}

